    // NOTE TO CODE GENERATOR MAINTAINER:
    // packedSize() and stringParamOffset() are kept in sync with pack() by the generator.
    // When adding a new command to the JSON, regenerate to update all three.

    // Returns total bytes that pack() writes for the given commandType,
    // INCLUDING the 2-byte commandType prefix.
    // Returns 0xFF (STRING_SENTINEL) if the command has a string parameter.
    // Returns 0 for unknown command types.
    static uint8_t packedSize(uint16_t commandType) {
        switch (commandType) {
            case 0xFF00: return 2;
            case 0xFD00: return 2;
            case 0xFD01: return 3;
            case 0xFC00: return 2;
            case 0xFC01: return 3;
            case ChassisCommandType::MOVE: return 6;
            case ChassisCommandType::STOP: return 2;
            case ChassisCommandType::FORWARD: return 3;
            case ChassisCommandType::BACKWARD: return 3;
            case ChassisCommandType::TURN_LEFT: return 3;
            case ChassisCommandType::TURN_RIGHT: return 3;
            case ChassisCommandType::SET_SPEED: return 4;
            case ChassisCommandType::SEND_ID: return 6;
            case ChassisCommandType::DISCOVERY: return 2;
            case EspCommandType::TURNON_BUILTIN_LED: return 2;
            case EspCommandType::TURNOFF_BUILTIN_LED: return 2;
            case IndicatorBoardCommandType::OLED_PRINT_STR: return 0xFF; // string param — variable length
            case IndicatorBoardCommandType::OLED_DRAW_FRAME: return 8;
            case IndicatorBoardCommandType::OLED_DRAW_BAR: return 7;
            case IndicatorBoardCommandType::OLED_CLEAR: return 2;
            case IndicatorBoardCommandType::OLED_REFRESH: return 2;
            case IndicatorBoardCommandType::OLED_SET_BRIGHTNESS: return 3;
            case IndicatorBoardCommandType::LED_SET_BLOCK: return 4;
            case IndicatorBoardCommandType::LED_SET_SINGLE: return 6;
            case IndicatorBoardCommandType::BEEP: return 4;
            case IndicatorBoardCommandType::RESET: return 3;
            case IndicatorBoardCommandType::OLED_SET_FONT: return 3;
            case IndicatorBoardCommandType::OLED_SET_CURSOR: return 6;
            case IndicatorBoardCommandType::SEND_ID: return 6;
            case IndicatorBoardCommandType::DISCOVERY: return 2;
            case IndicatorBoardCommandType::TURNON_BUILTIN_LED: return 2;
            case IndicatorBoardCommandType::TURNOFF_BUILTIN_LED: return 2;
            case TempBoardCommandType::LED_SET: return 3;
            case TempBoardCommandType::LED_RED_ON: return 2;
            case TempBoardCommandType::LED_RED_OFF: return 2;
            case TempBoardCommandType::LED_GREEN_ON: return 2;
            case TempBoardCommandType::LED_GREEN_OFF: return 2;
            case TempBoardCommandType::SEND_ID: return 6;
            case TempBoardCommandType::DISCOVERY: return 2;
            case EspCommandType::GET_BOARD_VOLTAGE: return 2;
            case EspCommandType::GET_BOARD_TEMPERATURE: return 2;
            case IndicatorBoardCommandType::GET_DISPLAY_BRIGHTNESS: return 2;
            case IndicatorBoardCommandType::GET_LED_COUNT: return 2;
            case TempBoardCommandType::GET_TEMPERATURE: return 2;
            case ChassisCommandType::GET_SETTING_MAX_SPEED: return 2;
            case ChassisCommandType::SET_SETTING_MAX_SPEED: return 3;
            case EspCommandType::GET_SETTING_WIFI_CHANNEL: return 2;
            case EspCommandType::SET_SETTING_WIFI_CHANNEL: return 3;
            case EspCommandType::GET_SETTING_TELEMETRY_INTERVAL_MS: return 2;
            case EspCommandType::SET_SETTING_TELEMETRY_INTERVAL_MS: return 6;
            case EspCommandType::GET_SETTING_DEVICE_NAME: return 2;
            case EspCommandType::SET_SETTING_DEVICE_NAME: return 0xFF;
            case IndicatorBoardCommandType::GET_SETTING_OLED_BRIGHTNESS: return 2;
            case IndicatorBoardCommandType::SET_SETTING_OLED_BRIGHTNESS: return 3;
            case IndicatorBoardCommandType::GET_SETTING_OLED_CONTRAST: return 2;
            case IndicatorBoardCommandType::SET_SETTING_OLED_CONTRAST: return 3;
            case IndicatorBoardCommandType::GET_SETTING_DEFAULT_FONT: return 2;
            case IndicatorBoardCommandType::SET_SETTING_DEFAULT_FONT: return 3;
            case IndicatorBoardCommandType::GET_SETTING_LED_DEFAULT_COLOR: return 2;
            case IndicatorBoardCommandType::SET_SETTING_LED_DEFAULT_COLOR: return 4;
            case IndicatorBoardCommandType::GET_SETTING_BUZZER_ENABLED: return 2;
            case IndicatorBoardCommandType::SET_SETTING_BUZZER_ENABLED: return 3;
            case TempBoardCommandType::GET_SETTING_TEMP_INTERVAL_MS: return 2;
            case TempBoardCommandType::SET_SETTING_TEMP_INTERVAL_MS: return 4;
            case TempBoardCommandType::GET_SETTING_TEMP_THRESHOLD_HIGH: return 2;
            case TempBoardCommandType::SET_SETTING_TEMP_THRESHOLD_HIGH: return 4;
            case TempBoardCommandType::GET_SETTING_AUTO_LED_MODE: return 2;
            case TempBoardCommandType::SET_SETTING_AUTO_LED_MODE: return 3;
            default: return 0;
        }
    }

    // Returns the byte offset from the start of the payload (after the header byte)
    // where the string parameter's typeAndSize byte can be found.
    // Only meaningful when packedSize() returns 0xFF.
    // Returns 0 for non-string commands.
    static uint8_t stringParamOffset(uint16_t commandType) {
        switch (commandType) {
            case IndicatorBoardCommandType::OLED_PRINT_STR: return 7; // seqNum(1) + commandType(2) + x(2) + y(2)
            default: return 0;
        }
    }

